// Telegram Business: a connected bot answers in the real account's DMs.
// updates arrive as business_message; replies must carry business_connection_id.
const u = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const bm = u.business_message || u.edited_business_message || u.message || {};
const from = bm.from || {}; const chat = bm.chat || {};
const text = (bm.text || bm.caption || '').toString().trim();
const bcid = bm.business_connection_id || '';
// only the chat partner in a private business chat: skips the owner's own outgoing
// messages and the bot's own sends (both have from.id != chat.id) -> no loops.
if (!bcid) return [];
if (chat.type && chat.type !== 'private') return [];
if (from.is_bot) return [];
if (String(from.id || '') !== String(chat.id || '')) return [];
const display = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'him';
const username = (from.username || String(from.id || '') || display || 'unknown').toString().toLowerCase();
const chat_id = String(chat.id || from.id || '');
const interaction = String(bm.message_id || '');
const photos = Array.isArray(bm.photo) ? bm.photo : null;
const photo_file_id = (photos && photos.length) ? photos[photos.length - 1].file_id : '';
const voice_file_id = (bm.voice && bm.voice.file_id) || (bm.audio && bm.audio.file_id) || '';
let mediaMarker = '';
if (bm.video || bm.video_note) mediaMarker = '[he just sent you a video]';
else if (bm.animation) mediaMarker = '[he just sent you a gif]';
else if (bm.sticker) mediaMarker = '[he just sent you a sticker' + (bm.sticker.emoji ? ' ' + bm.sticker.emoji : '') + ']';
else if (bm.document) mediaMarker = '[he just sent you a file' + (bm.document.file_name ? ': ' + bm.document.file_name : '') + ']';
else if (bm.location) mediaMarker = '[he just shared his location]';
else if (bm.contact) mediaMarker = '[he just shared a contact]';
let msg = text;
if (!msg) {
  if (photo_file_id) msg = '[he just sent you a photo]';
  else if (voice_file_id) msg = '[he just sent you a voice note]';
  else if (mediaMarker) msg = mediaMarker;
  else msg = '(he sent an empty message, greet him and tease him lightly)';
}
return [{ json: { username: username, display: display, chat_id: chat_id, business_connection_id: bcid, photo_file_id: photo_file_id, voice_file_id: voice_file_id, msg: msg, interaction: interaction } }];

// duplicate guard: if the bridge ever re-delivers the same message (same
// message_id) for this fan, drop it so she does not reply twice.
const ex = $('Extract Inbound').first().json;
const items = $('Dedup: read fan').all();
let meta = {};
if (items.length === 1 && Array.isArray(items[0].json)) { if (items[0].json.length) meta = items[0].json[0].metadata || {}; }
else if (items.length && items[0].json && items[0].json.metadata) { meta = items[0].json.metadata || {}; }
const last = (meta && meta.last_interaction_ts) ? String(meta.last_interaction_ts) : '';
const cur = ex.interaction ? String(ex.interaction) : '';
if (cur && last && cur === last) { return []; }
return [{ json: ex }];

// human-feeling delay + pause gate, PER-PERSONA. timing comes from
// bots.reply_delay and the pause from bots.automation_paused (admin dashboard),
// both returned by dm_ingest. Telegram has its own reply_delay (more present
// than tiktok). Same convention as the live ManyChat workflow.
const ctx = $('DB: ingest').first().json || {};
// pause: dashboard toggled this bot off -> inbound already logged, don't queue/reply.
if (ctx.automation_paused === true) { return []; }
const d = ctx.reply_delay || {};
const num = (v, dft) => (Number.isFinite(Number(v)) ? Number(v) : dft);
const minS = num(d.min_sec, 45);
const maxS = num(d.max_sec, 240);
const qP   = num(d.quick_chance, 0.30);
const qMin = num(d.quick_min_sec, 15);
const qMax = num(d.quick_max_sec, 60);
let sec;
if (Math.random() < qP) { sec = Math.round(qMin + Math.random() * Math.max(0, qMax - qMin)); }
else { sec = Math.round(minS + Math.random() * Math.max(0, maxS - minS)); }
const ex = $('Extract Inbound').first().json || {};
let _dmsg = ex.msg;
try { const _a=$('Photo: describe apply').first().json; if (_a && _a.msg) _dmsg = _a.msg; } catch (e) {}
try { const _v=$('Voice: apply').first().json; if (_v && _v.msg) _dmsg = _v.msg; } catch (e) {}
const now = Date.now();
return [{ json: { delaySec: sec, myCount: ctx.count, fan_id: ctx.fan_id, bot_id: ctx.bot_id, chat_id: ex.chat_id, business_connection_id: ex.business_connection_id, photo_file_id: ex.photo_file_id, username: ex.username, display: ex.display, msg: _dmsg, queued_at: new Date(now).toISOString(), scheduled_for: new Date(now + sec * 1000).toISOString() } }];

// debounce: only the LAST inbound message in a burst gets to reply.
// if msg_count grew while we were waiting, a newer message arrived;
// abort this run (return []) and let the newer run answer with full context.
const arr = $('DB: get fan').first().json;
const cur = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
const myCount = $('Set Delay').first().json.myCount;
if (typeof cur.msg_count !== 'number' || cur.msg_count !== myCount) { return []; }
return [{ json: { proceed: true } }];

