const _pcLast = (function(){ for (let i = recent.length - 1; i >= 0; i--) { if (recent[i] && recent[i].role === 'user') return String(recent[i].content || ''); } return ''; })().toLowerCase();
if (gOn('paid_content_line') && /(onlyfans|only fans|content|nudes|nude|pics|pictures|subscribe|premium|do you sell|what do i get|what would i get|paid|snap)/i.test(_pcLast)) { messages.push({ role: 'system', content: gText('paid_content_line', 'PAID CONTENT: if he asks about onlyfans, paid content, subscribing, or what he gets: you are NOT on onlyfans, and be honest why, you dont want your family finding out. but you do have some content on offer here. keep it light and coy, never explicit, never name a price, never a hard sell, just hint that its there.') }); }
